const data = items[0].json;

// 🔹 Nome
const nomeUsuario = data.nome || "";

// 🔹 Contexto
const contexto = data.contexto || "";

// 🔹 Resultados
const resultados = data.resultados || [];

// 🔹 Código OTP (6 dígitos)
const codigo = data.codigo || "";

// 🔹 URL para completar cadastro
const completarCadastroUrl = data.completar_cadastro_url || "";

// 🔹 Número
const numero = data.telefone || data.numero;

// 🔹 Separar por escopo
const nacionais = resultados.filter(r => r.item?.escopo === "nacional");
const locais = resultados.filter(r => r.item?.escopo === "local");

// 🔹 Ordenar por nota
const ordenarPorNota = (arr) =>
  [...arr].sort((a, b) => (b.item?.nota ?? 0) - (a.item?.nota ?? 0));

// 🔹 Selecionar 2 de cada
const topNacionais = ordenarPorNota(nacionais).slice(0, 2);
const topLocais = ordenarPorNota(locais).slice(0, 2);

// 🔹 Função de formatação
const formatarLista = (lista) => {
  return lista
    .map((r, i) => {
      const item = r.item || {};
      const nome = item.razao_social || "Fornecedor";
      const modelo = item.modelo_negocio ? ` (${item.modelo_negocio})` : "";
      const site = item.site ? `\n${item.site}` : "";
      return `${i + 1}. ${nome}${modelo}${site}`;
    })
    .join("\n\n");
};

// 🔹 Blocos separados
let blocoNacionais = "";
if (topNacionais.length > 0) {
  blocoNacionais = `🌎 *Fornecedores Nacionais*\n\n${formatarLista(topNacionais)}`;
}

let blocoLocais = "";
if (topLocais.length > 0) {
  blocoLocais = `📍 *Fornecedores Locais*\n\n${formatarLista(topLocais)}`;
}

// 🔹 Contagem restante
const totalExibidos = topNacionais.length + topLocais.length;
const totalRestante = Math.max(0, resultados.length - totalExibidos);

// 🔹 Linha de contexto
const linhaContexto = contexto
  ? `Separei alguns fornecedores pra "${contexto}".`
  : "Separei alguns fornecedores pra você.";

// 🔹 Mensagem
let mensagem = `${linhaContexto}`;

// 🔹 Inserir blocos
if (blocoNacionais) {
  mensagem += `\n\n${blocoNacionais}`;
}

if (blocoLocais) {
  mensagem += `\n\n${blocoLocais}`;
}

// 🔹 CTA com OTP (mantido)
if (totalRestante > 0) {
  mensagem += `

Tem mais ${totalRestante} no site, com contato e detalhes completos. Pra acessar é só confirmar seu número:`;
} else {
  mensagem += `

Pra ver os contatos e detalhes completos, é só confirmar seu número:`;
}

mensagem += `

Seu código é *${codigo}*

${completarCadastroUrl}

(o código vale por 15 minutos)

Qualquer coisa, pode me chamar por aqui.`;

// 🔹 Retorno
return [
  {
    json: {
      number: numero,
      text: mensagem
    }
  }
];

